sql:
SELECT day_of_week, COUNT(*) AS matches_played
     FROM match_analysis
     GROUP BY day_of_week;

SELECT AVG(match_rating) AS avg_high_shots_match_rating
FROM match_analysis
WHERE shots_on_target > (
  SELECT AVG(shots_on_target) 
  FROM match_analysis
);

SELECT match_date, (goals_for - goals_against) AS goal_difference
FROM match_analysis
ORDER BY goal_difference DESC;

SELECT match_date, result
FROM match_analysis
ORDER BY match_date ASC;

SELECT AVG(yellow_cards) AS avg_yellow_cards
FROM match_analysis
WHERE home_away = 'Home' AND result = 'L' AND attendance > 20000;

